import React, { forwardRef } from 'react';
import clsx from 'clsx';
import type { BaseProps } from './Layout';
import { useCssScope } from '../config-provider/hooks';

import './style';

const Header = forwardRef<HTMLElement, BaseProps>((props, ref) => {
  const { className, children, ...restProps } = props;
  const cssScope = useCssScope('layout__header');
  const cls = clsx(
    {
      [cssScope()]: true,
    },
    className,
  );

  return (
    <header ref={ref} className={cls} {...restProps}>
      {children}
    </header>
  );
});

export default Header;
